SELECT DISTINCT state AS value, state AS label
FROM bill_management_v2.locations
WHERE customer_id = {{ Number(CustomerSelect.selectedOptionValue) || 94512 }}
  AND state IS NOT NULL AND state <> ''
  {{ CountrySelect.selectedOptionValues && CountrySelect.selectedOptionValues.length > 0 ? "AND country IN ('" + CountrySelect.selectedOptionValues.join("','") + "')" : "" }}
ORDER BY state;
